import{_ as o,c as e,o as i,ag as a}from"./chunks/framework.D4Vqf8I7.js";const g=JSON.parse('{"title":"Kirikiri","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/kirikiri.md","filePath":"docs/wi/games/kirikiri.md","lastUpdated":1782128211000}'),r={name:"docs/wi/games/kirikiri.md"};function d(l,t,s,n,c,h){return i(),e("div",null,t[0]||(t[0]=[a(`<h1 id="kirikiri" tabindex="-1">Kirikiri <a class="header-anchor" href="#kirikiri" aria-label="Permalink to &quot;Kirikiri&quot;">​</a></h1><h2 id="общая-информация" tabindex="-1">Общая информация <a class="header-anchor" href="#общая-информация" aria-label="Permalink to &quot;Общая информация&quot;">​</a></h2><p><strong>Kirikiri</strong> (произносится «Кирикири», яп. 吉里吉里) — это скриптовый движок для создания визуальных новелл и кинетических новелл, разработанный японским программистом <strong>W.Dee</strong> и впервые выпущенный в 1998 году [[17]].</p><p>Движок практически всегда используется в связке с фреймворком <strong>KAG (Kirikiri Adventure Game System)</strong> — системой скриптов, специально разработанной для упрощения создания визуальных новелл [[9]].</p><blockquote><p><strong>Интересный факт</strong>: Название «Кирикири» — это звукоподражание японскому крику сверчка, символизирующее лёгкость и изящество движка.</p></blockquote><h2 id="архитектура-и-технологии" tabindex="-1">Архитектура и технологии <a class="header-anchor" href="#архитектура-и-технологии" aria-label="Permalink to &quot;Архитектура и технологии&quot;">​</a></h2><h3 id="двухуровневая-система" tabindex="-1">Двухуровневая система <a class="header-anchor" href="#двухуровневая-система" aria-label="Permalink to &quot;Двухуровневая система&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│   Сценарий (.ks)        │ ← Пишет сценарист (KAG-теги)</span></span>
<span class="line"><span>│   [KAG Framework]       │</span></span>
<span class="line"><span>└─────────┬───────────────┘</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│   Скрипты (.tjs)        │ ← Пишет программист (TJS2)</span></span>
<span class="line"><span>│   [TJS2 Interpreter]    │</span></span>
<span class="line"><span>└─────────┬───────────────┘</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│   Ядро Kirikiri         │ ← Рендеринг, ввод, аудио</span></span>
<span class="line"><span>│   [Native C++ Core]     │</span></span>
<span class="line"><span>└─────────────────────────┘</span></span></code></pre></div><h3 id="ключевые-компоненты" tabindex="-1">Ключевые компоненты: <a class="header-anchor" href="#ключевые-компоненты" aria-label="Permalink to &quot;Ключевые компоненты:&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Компонент</th><th>Описание</th></tr></thead><tbody><tr><td><strong>KAG</strong></td><td>Высокоуровневый язык сценариев с тегами, похожими на HTML (<code>[backlog]</code>, <code>[image]</code>, <code>[button]</code>) [[9]]</td></tr><tr><td><strong>TJS2</strong></td><td>Объектно-ориентированный скриптовый язык, на котором написан сам KAG; позволяет расширять функционал движка</td></tr><tr><td><strong>XP3</strong></td><td>Проприетарный формат архивов для упаковки всех ресурсов игры [[4]]</td></tr></tbody></table><hr><h2 id="форматы-фаилов" tabindex="-1">Форматы файлов <a class="header-anchor" href="#форматы-фаилов" aria-label="Permalink to &quot;Форматы файлов&quot;">​</a></h2><h3 id="основные-расширения" tabindex="-1">Основные расширения: <a class="header-anchor" href="#основные-расширения" aria-label="Permalink to &quot;Основные расширения:&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Расширение</th><th>Назначение</th></tr></thead><tbody><tr><td><code>.xp3</code></td><td>Архив с данными игры (изображения, звук, скрипты) [[21]]</td></tr><tr><td><code>.ks</code></td><td>Файл сценария на языке KAG (Kirikiri Script)</td></tr><tr><td><code>.tjs</code></td><td>Скрипт на языке TJS2 для расширенной логики</td></tr><tr><td><code>.tlg</code></td><td>Проприетарный формат изображений Kirikiri (часто конвертируется в PNG)</td></tr><tr><td><code>.sig</code></td><td>Файл цифровой подписи/проверки целостности архива [[24]]</td></tr></tbody></table><h3 id="структура-типичнои-игры" tabindex="-1">Структура типичной игры: <a class="header-anchor" href="#структура-типичнои-игры" aria-label="Permalink to &quot;Структура типичной игры:&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GameFolder/</span></span>
<span class="line"><span>├── data.xp3          # Основные ресурсы</span></span>
<span class="line"><span>├── patch.xp3         # Обновления/патчи</span></span>
<span class="line"><span>├── krkr.exe          # Исполняемый файл движка</span></span>
<span class="line"><span>├── plugin/           # Дополнительные модули</span></span>
<span class="line"><span>└── save/             # Сохранения игрока</span></span></code></pre></div><blockquote><p>Все данные игры упакованы в <code>.xp3</code>-архивы. Для извлечения требуются специальные утилиты вроде <code>Garbro</code>, <code>krkrextract</code> или <code>Xp3Pack</code> [[1]][[26]].</p></blockquote><h2 id="особенности-и-преимущества" tabindex="-1">Особенности и преимущества <a class="header-anchor" href="#особенности-и-преимущества" aria-label="Permalink to &quot;Особенности и преимущества&quot;">​</a></h2><h3 id="🔹-гибкость" tabindex="-1">🔹 Гибкость <a class="header-anchor" href="#🔹-гибкость" aria-label="Permalink to &quot;🔹 Гибкость&quot;">​</a></h3><ul><li><strong>Расширяемость через TJS2</strong>: Поскольку KAG написан на TJS2, разработчики могут модифицировать сам фреймворк или напрямую обращаться к ядру движка [[9]].</li><li><strong>Поддержка плагинов</strong>: Можно подключать внешние DLL-модули для добавления новой функциональности.</li></ul><h3 id="🔹-кроссплатформенность" tabindex="-1">🔹 Кроссплатформенность <a class="header-anchor" href="#🔹-кроссплатформенность" aria-label="Permalink to &quot;🔹 Кроссплатформенность&quot;">​</a></h3><ul><li>Изначально разработан для Windows, но существуют порты: <ul><li><strong>Kirikiroid2</strong> — для Android</li><li><strong>Kirikiri Z</strong> — современная форк-версия с поддержкой новых ОС [[7]]</li></ul></li></ul><h3 id="🔹-производительность" tabindex="-1">🔹 Производительность <a class="header-anchor" href="#🔹-производительность" aria-label="Permalink to &quot;🔹 Производительность&quot;">​</a></h3><ul><li>Оптимизирован для 2D-рендера: спрайты, переходы, эффекты</li><li>Поддержка аппаратного ускорения (в более новых версиях)</li></ul><h3 id="🔹-локализация" tabindex="-1">🔹 Локализация <a class="header-anchor" href="#🔹-локализация" aria-label="Permalink to &quot;🔹 Локализация&quot;">​</a></h3><ul><li>Поддержка различных кодировок: Shift-JIS (для японских игр), UTF-8/UTF-16 (для международных версий) [[3]]</li><li>Возможность подмены шрифтов для отображения кириллицы и других алфавитов</li></ul><h2 id="известные-игры-на-kirikiri" tabindex="-1">Известные игры на Kirikiri <a class="header-anchor" href="#известные-игры-на-kirikiri" aria-label="Permalink to &quot;Известные игры на Kirikiri&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Игра</th><th>Студия</th><th>Примечание</th></tr></thead><tbody><tr><td><strong>Fate/stay night</strong></td><td>TYPE-MOON</td><td>Одна из самых известных ВН на движке</td></tr><tr><td><strong>Fate/hollow ataraxia</strong></td><td>TYPE-MOON</td><td>Продолжение Fate/stay night</td></tr><tr><td><strong>Nekopara</strong></td><td>NEKO WORKs</td><td>Использует модифицированную версию, доступна в Steam</td></tr><tr><td><strong>1999 Christmas Eve</strong></td><td>—</td><td>Классическая новелла на Kirikiri</td></tr><tr><td><strong>Maji de Watashi ni Koi Shinasai!</strong></td><td>Minato Soft</td><td>Популярная коммерческая ВН</td></tr></tbody></table><p>Движок широко используется как в <strong>додзин-проектах</strong> (любительских), так и в <strong>коммерческих визуальных новеллах</strong> [[15]].</p><h2 id="версии-и-развитие" tabindex="-1">Версии и развитие <a class="header-anchor" href="#версии-и-развитие" aria-label="Permalink to &quot;Версии и развитие&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Версия</th><th>Год</th><th>Статус</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Kirikiri 1</strong></td><td>1998</td><td>Устарела</td><td>Базовая функциональность</td></tr><tr><td><strong>Kirikiri 2 + KAG3</strong></td><td>~2003</td><td>Наиболее распространённая</td><td>Полная переработка, обратная совместимость на уровне сценариев [[9]]</td></tr><tr><td><strong>Kirikiri Z</strong></td><td>2013+</td><td>Активная форк-версия</td><td>Поддержка современных ОС, улучшения рендерера [[7]]</td></tr></tbody></table><blockquote><p>С октября 2010 года оригинальный Kirikiri не обновлялся. С 2013 года развитие продолжилось в виде форка <strong>Kirikiri Z</strong> [[15]].</p></blockquote><h2 id="для-переводчиков-и-моддеров" tabindex="-1">Для переводчиков и моддеров <a class="header-anchor" href="#для-переводчиков-и-моддеров" aria-label="Permalink to &quot;Для переводчиков и моддеров&quot;">​</a></h2><h3 id="основные-инструменты" tabindex="-1">Основные инструменты: <a class="header-anchor" href="#основные-инструменты" aria-label="Permalink to &quot;Основные инструменты:&quot;">​</a></h3><ul><li><strong>Garbro</strong> — универсальный экстрактор архивов, поддерживает XP3 [[1]]</li><li><strong>KirikiriTools</strong> (GitHub) — набор утилит: <code>Xp3Pack</code> для создания патчей, <code>KirikiriDescrambler</code> для расшифровки скриптов [[1]]</li><li><strong>VNTextPatch</strong> — инструмент для патчинга текста без переупаковки архивов [[1]]</li><li><strong>Translator++</strong> — специализированный редактор с поддержкой KAG-тегов [[4]]</li></ul><h3 id="типичные-сложности" tabindex="-1">Типичные сложности: <a class="header-anchor" href="#типичные-сложности" aria-label="Permalink to &quot;Типичные сложности:&quot;">​</a></h3><ol><li><strong>Шифрование/скремблинг</strong> скриптов — некоторые игры защищают <code>.ks</code>-файлы сигнатурами <code>FE FE 00 FF FE</code> и др. [[1]]</li><li><strong>Кодировки</strong> — старые игры используют Shift-JIS, новые — UTF-8; ошибка приведёт к нечитаемому тексту [[3]]</li><li><strong>Длина текста</strong> — русский/английский текст длиннее японского; может потребоваться разбивка строк или правка окон диалога</li><li><strong>Шрифты</strong> — встроенные шрифты могут не поддерживать кириллицу; иногда требуется подмена через конфигурацию</li></ol><h2 id="ресурсы-для-изучения" tabindex="-1">Ресурсы для изучения <a class="header-anchor" href="#ресурсы-для-изучения" aria-label="Permalink to &quot;Ресурсы для изучения&quot;">​</a></h2><ul><li>🌐 <a href="https://kirikirikag.sourceforge.net/" target="_blank" rel="noreferrer">Официальная документация KAG</a> — справочник по тегам и примерам [[9]]</li><li>💻 <a href="https://github.com/arcusmaximus/KirikiriTools" target="_blank" rel="noreferrer">KirikiriTools на GitHub</a> — инструменты для работы с движком [[1]]</li><li>🗣️ <a href="https://lemmasoft.renai.us/" target="_blank" rel="noreferrer">Lemma Soft Forums</a> — сообщество локализаторов, гайды по Kirikiri [[2]]</li><li>📖 <a href="https://dreamsavior.net/docs/translator/kirikiri-kag/" target="_blank" rel="noreferrer">Dreamsavior: KiriKiri/KAG Guide</a> — практические советы по переводу [[4]]</li></ul><h2 id="паиплаин-перевода-игр-на-kirikiri2" tabindex="-1">Пайплайн перевода игр на Kirikiri2 <a class="header-anchor" href="#паиплаин-перевода-игр-на-kirikiri2" aria-label="Permalink to &quot;Пайплайн перевода игр на Kirikiri2&quot;">​</a></h2><h3 id="🔹-этап-1-разведка-и-подготовка" tabindex="-1">🔹 Этап 1: Разведка и подготовка <a class="header-anchor" href="#🔹-этап-1-разведка-и-подготовка" aria-label="Permalink to &quot;🔹 Этап 1: Разведка и подготовка&quot;">​</a></h3><p><strong>Цель:</strong> Понять структуру игры, проверить защиту, подготовить рабочее окружение.</p><ol><li>Определить версию движка (<code>krkr.exe</code>, <code>data.xp3</code>, наличие <code>plugin/</code>, <code>config.tjs</code>).</li><li>Проверить наличие защиты: скремблинг скриптов, шифрование XP3, проверка подписи (<code>.sig</code>), модифицированный экзешник.</li><li>Найти гайды по конкретной игре на <strong>LemmaSoft Forums</strong>, <strong>Fuwanovel</strong>, <strong>GitHub</strong> или <strong>VNDB</strong>.</li><li>Создать чистую рабочую директорию: <code>original/</code>, <code>extracted/</code>, <code>translated/</code>, <code>patch/</code>.</li></ol><p><strong>Инструменты:</strong></p><ul><li><code>Detect It Easy (DIE)</code> или <code>PEiD</code> → анализ <code>krkr.exe</code></li><li><code>Garbro</code> → быстрый просмотр содержимого <code>.xp3</code></li><li><code>Strings</code> / <code>HxD</code> → поиск ключевых слов (<code>KAG</code>, <code>TJS</code>, <code>XP3</code>)</li><li>Поисковые запросы: <code>[GameName] Kirikiri extract</code>, <code>KAG script decryption</code></li></ul><h3 id="🔹-этап-2-извлечение-ресурсов" tabindex="-1">🔹 Этап 2: Извлечение ресурсов <a class="header-anchor" href="#🔹-этап-2-извлечение-ресурсов" aria-label="Permalink to &quot;🔹 Этап 2: Извлечение ресурсов&quot;">​</a></h3><p><strong>Цель:</strong> Получить доступ к скриптам, текстам и графике без повреждения структуры.</p><ol><li>Распаковать <code>.xp3</code> архивы в отдельную папку.</li><li>Сохранить оригинальную иерархию папок (движок чувствителен к путям).</li><li>Если архив зашифрован/скремблирован: применить дамп памяти или специфичный для игры декриптор.</li></ol><p><strong>Инструменты:</strong></p><ul><li><code>Garbro</code> (GUI, поддерживает XP3, TLG, WAV)</li><li><code>krkrextract</code> / <code>Xp3Dump</code> (консольные, быстрая распаковка)</li><li><code>QuickBMS</code> + скрипты (если нестандартная упаковка)</li><li><code>Textractor</code> → <strong>альтернативный метод</strong>: вытягивает текст напрямую из памяти запущенной игры (полезно, если скрипты зашифрованы)</li></ul><h3 id="🔹-этап-3-перевод-и-редактирование" tabindex="-1">🔹 Этап 3: Перевод и редактирование <a class="header-anchor" href="#🔹-этап-3-перевод-и-редактирование" aria-label="Permalink to &quot;🔹 Этап 3: Перевод и редактирование&quot;">​</a></h3><p><strong>Цель:</strong> Перевести текст, сохранить синтаксис KAG, подготовить графику и шрифты.</p><ol><li>Определить кодировку <code>.ks</code> файлов: <code>Shift-JIS</code> (старые японские игры) или <code>UTF-8</code>/<code>UTF-16</code> (новые/порты).</li><li>Открыть файлы в редакторе с поддержкой кодировок. <strong>Не менять</strong>: <ul><li>Теги KAG: <code>[r]</code>, <code>[l]</code>, <code>[p]</code>, <code>[if]</code>, <code>[iscript]</code>, <code>*label</code>, <code>@jump</code></li><li>Переменные: <code>f.name</code>, <code>sf.scene</code>, <code>mp.char</code></li><li>Системные вызовы</li></ul></li><li>Перевести текст, сохраняя структуру вызовов <code>text=&quot;...&quot;</code>. Если текст длиннее оригинала, разбить на несколько строк или использовать <code>[ruby]</code>/<code>[nowrap]</code>.</li><li>Отредактировать изображения с текстом (меню, заставки, логотипы).</li><li>Подготовить шрифт с поддержкой кириллицы (если движок использует встроенный).</li></ol><p><strong>Инструменты:</strong></p><ul><li><code>Notepad++</code> / <code>VS Code</code> → редактирование <code>.ks</code>, подсветка синтаксиса</li><li><code>Translator++</code> → CAT-инструмент с поддержкой KAG-тегов, экспорт/импорт в таблицы</li><li><code>OmegaT</code> / <code>Smartcat</code> → для командной работы и глоссариев</li><li><code>Photoshop</code> / <code>GIMP</code> / <code>Krita</code> → правка графики</li><li><code>FontForge</code> / <code>Noto Sans</code> → подготовка шрифтов</li><li><code>Textractor</code> + <code>Textractor CLI</code> → автоматический сбор текста для перевода в CSV</li></ul><h3 id="🔹-этап-4-интеграция-и-сборка" tabindex="-1">🔹 Этап 4: Интеграция и сборка <a class="header-anchor" href="#🔹-этап-4-интеграция-и-сборка" aria-label="Permalink to &quot;🔹 Этап 4: Интеграция и сборка&quot;">​</a></h3><p><strong>Цель:</strong> Вернуть переведённые файлы в игру, не сломав логику.</p><ol><li>Запаковать изменённые файлы обратно в <code>.xp3</code> с <strong>идентичной структурой</strong>.</li><li>Если игра проверяет целостность (<code>.sig</code> или хеш-суммы): <ul><li>Использовать патчер, игнорирующий проверки</li><li>Или заменить <code>data.xp3</code> полностью, если игра не использует внешнюю валидацию</li></ul></li><li>Настроить шрифт: <ul><li>В <code>data.tjs</code> или <code>config.tjs</code> изменить путь к шрифту на системный (<code>&quot;C:/Windows/Fonts/arial.ttf&quot;</code>)</li><li>Или использовать DLL-инжектор шрифтов (например, <code>Kirikiri Font Changer</code>)</li></ul></li><li>Создать патч или модифицированную сборку.</li></ol><p><strong>Инструменты:</strong></p><ul><li><code>Garbro</code> → повторная упаковка</li><li><code>Xp3Pack</code> (из KirikiriTools) → точная сборка с сохранением метаданных</li><li><code>HxD</code> / <code>010 Editor</code> → правка заголовков, обход простых проверок</li><li><code>Kirikiri Font Patcher</code> → замена шрифтов без правки скриптов</li><li><code>Inno Setup</code> / <code>7-Zip SFX</code> → создание установщика патча</li></ul><h3 id="🔹-этап-5-тестирование-и-отладка" tabindex="-1">🔹 Этап 5: Тестирование и отладка <a class="header-anchor" href="#🔹-этап-5-тестирование-и-отладка" aria-label="Permalink to &quot;🔹 Этап 5: Тестирование и отладка&quot;">​</a></h3><p><strong>Цель:</strong> Убедиться, что игра стабильна, текст отображается корректно, нет вылетов.</p><ol><li>Запуск с отладочным флагом: <code>krkr.exe -debug</code> или <code>debug=1</code> в конфиге.</li><li>Проверка: <ul><li>Загрузка всех сцен</li><li>Переполнение диалоговых окон</li><li>Корректность кодировки (нет &quot;кракозябр&quot;)</li><li>Работа сохранений и перемотки</li></ul></li><li>Сбор логов вылетов (обычно <code>error.log</code> в папке игры или <code>%APPDATA%</code>).</li><li>Фикс проблем: разбивка строк, правка тегов, замена шрифта, отключение проблемных плагинов.</li></ol><p><strong>Инструменты:</strong></p><ul><li>Встроенный отладчик Kirikiri2 (<code>-debug</code>, <code>log=1</code>)</li><li><code>Process Monitor</code> → отслеживание доступа к файлам</li><li><code>OBS Studio</code> / скриншоты → фиксация багов</li><li><code>Notepad++</code> с regex → массовая правка переполнений</li></ul><h3 id="🔹-этап-6-публикация-и-поддержка" tabindex="-1">🔹 Этап 6: Публикация и поддержка <a class="header-anchor" href="#🔹-этап-6-публикация-и-поддержка" aria-label="Permalink to &quot;🔹 Этап 6: Публикация и поддержка&quot;">​</a></h3><p><strong>Цель:</strong> Выпустить патч, документировать особенности, собрать фидбек.</p><ol><li>Упаковать патч с инструкцией по установке.</li><li>Написать <code>README.md</code>: версия движка, известные баги, требования, контакты.</li><li>Опубликовать на тематических площадках (VNDB, LemmaSoft, VK/Discord сообщества, itch.io).</li><li>Поддерживать обновления: фиксы, хотфиксы шрифтов, совместимость с обновлениями игры.</li></ol><p><strong>Инструменты:</strong></p><ul><li><code>Git</code> / <code>GitHub Releases</code> → версионирование патчей</li><li><code>Markdown</code> → документация</li><li><code>Discord</code> / <code>Telegram</code> → сообщество и баг-репорты</li></ul><h2 id="стартовыи-набор-инструментов-рекомендация" tabindex="-1">Стартовый набор инструментов (рекомендация) <a class="header-anchor" href="#стартовыи-набор-инструментов-рекомендация" aria-label="Permalink to &quot;Стартовый набор инструментов (рекомендация)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Категория</th><th>Инструмент</th><th>Зачем</th></tr></thead><tbody><tr><td><strong>Распаковка</strong></td><td><code>Garbro</code> + <code>krkrextract</code></td><td>Быстрое извлечение XP3/TLG</td></tr><tr><td><strong>Текст</strong></td><td><code>Translator++</code> + <code>Textractor</code></td><td>Извлечение, перевод, импорт/экспорт</td></tr><tr><td><strong>Редактирование</strong></td><td><code>VS Code</code> + <code>Notepad++</code></td><td>Правка <code>.ks</code> с подсветкой KAG</td></tr><tr><td><strong>Графика</strong></td><td><code>GIMP</code> / <code>Photoshop</code></td><td>Перевод меню, заставок</td></tr><tr><td><strong>Шрифты</strong></td><td><code>FontForge</code> + <code>Noto Sans</code></td><td>Подготовка кириллического шрифта</td></tr><tr><td><strong>Сборка</strong></td><td><code>Xp3Pack</code> + <code>Garbro</code></td><td>Обратная упаковка XP3</td></tr><tr><td><strong>Тест</strong></td><td><code>-debug</code> флаг + логи</td><td>Отлов вылетов и переполнений</td></tr><tr><td><strong>Публикация</strong></td><td><code>Inno Setup</code> + <code>Git</code></td><td>Создание патча и контроль версий</td></tr></tbody></table><h2 id="критические-советы" tabindex="-1">Критические советы <a class="header-anchor" href="#критические-советы" aria-label="Permalink to &quot;Критические советы&quot;">​</a></h2><ol><li><strong>Никогда не редактируй оригиналы напрямую.</strong> Всегда работай в копии.</li><li><strong>Соблюдай синтаксис KAG.</strong> Лишний пробел в теге <code>[if cond=&quot;true&quot;]</code> может сломать сцену.</li><li><strong>Тестируй инкрементально.</strong> Перевёл 1 файл → проверил → перешёл к следующему.</li><li><strong>Кодировка — главный враг.</strong> Открывай <code>.ks</code> строго в исходной кодировке. Сохраняй в той же.</li><li><strong>Длина текста.</strong> Японский текст в 1.5–2 раза короче русского. Используй <code>[r]</code> для переноса или уменьшай шрифт в окне диалога.</li><li><strong>Защита.</strong> Если игра не распаковывается стандартными утилитами, ищи специфичный декриптор или используй <code>Textractor</code> для прямого сбора текста из памяти.</li></ol><h2 id="где-искать-поддержку" tabindex="-1">Где искать поддержку <a class="header-anchor" href="#где-искать-поддержку" aria-label="Permalink to &quot;Где искать поддержку&quot;">​</a></h2><ul><li><strong>LemmaSoft.fo.ru / LemmaSoft Forums</strong> → разделы <code>Kirikiri</code>, <code>Translation Tools</code></li><li><strong>GitHub</strong>: <code>arcusmaximus/KirikiriTools</code>, <code>morkt/GARbro</code>, <code>Artikash/Textractor</code></li><li><strong>VNDB.org</strong> → страница игры → вкладка <code>Releases</code> → часто есть ссылки на патчи</li><li><strong>Discord</strong>: <code>VN Translation</code>, <code>Kirikiri Localization</code></li></ul>`,76)]))}const u=o(r,[["render",d]]);export{g as __pageData,u as default};
